"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { motion } from "framer-motion";

const sections = ["Overview", "Users", "Batches", "AI Usage", "Feature Toggles", "Content"];

const mockUsers = [
  { name: "Priya Sharma", email: "priya@example.com", role: "user", joined: "Mar 1", active: true },
  { name: "Arjun Kumar", email: "arjun@example.com", role: "user", joined: "Feb 28", active: true },
  { name: "Sneha Patel", email: "sneha@example.com", role: "user", joined: "Feb 20", active: false },
];

const features = [
  { key: "pdf_qa", label: "PDF Q&A System", enabled: true },
  { key: "mock_interview", label: "Mock Interview AI", enabled: true },
  { key: "code_execution", label: "Code Execution", enabled: true },
  { key: "group_study", label: "Group Study Rooms", enabled: false },
  { key: "edu_reels", label: "Educational Reels", enabled: true },
  { key: "multilingual", label: "Multilingual Mode", enabled: false },
];

export default function AdminPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [section, setSection] = useState("Overview");
  const [toggles, setToggles] = useState(features.reduce((acc, f) => ({ ...acc, [f.key]: f.enabled }), {} as Record<string, boolean>));

  useEffect(() => {
    if (status === "unauthenticated") router.push("/auth");
  }, [status, router]);

  if (status === "loading") return <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: "var(--bg-primary)", color: "white" }}>Loading...</div>;

  return (
    <div style={{ minHeight: "100vh", background: "var(--bg-primary)", display: "flex" }}>
      {/* Admin Sidebar */}
      <aside style={{ width: 240, background: "rgba(10,10,20,0.95)", borderRight: "1px solid rgba(255,255,255,0.06)", padding: "24px 12px", display: "flex", flexDirection: "column" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 32, padding: "0 8px" }}>
          <div style={{ width: 32, height: 32, borderRadius: 8, background: "linear-gradient(135deg,#FF6B9D,#6C63FF)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16 }}>⚙️</div>
          <div>
            <div style={{ fontSize: 14, fontWeight: 800, color: "white" }}>Admin Panel</div>
            <div style={{ fontSize: 11, color: "rgba(255,255,255,0.4)" }}>Tulasi AI</div>
          </div>
        </div>
        {sections.map(s => (
          <button key={s} onClick={() => setSection(s)} style={{
            display: "flex", alignItems: "center", gap: 10, padding: "10px 14px", borderRadius: 10, border: "none", cursor: "pointer", fontSize: 13, fontWeight: 500, textAlign: "left", transition: "all 0.2s", marginBottom: 2,
            background: section === s ? "rgba(108,99,255,0.15)" : "transparent",
            color: section === s ? "#6C63FF" : "rgba(255,255,255,0.6)",
          }}>{s}</button>
        ))}
      </aside>

      {/* Main */}
      <div style={{ flex: 1, padding: 32, overflowY: "auto" }}>
        <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} key={section}>
          {section === "Overview" && (
            <div>
              <h1 style={{ fontSize: 24, fontWeight: 800, fontFamily: "Outfit", marginBottom: 28 }}>📊 Platform Overview</h1>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(180px, 1fr))", gap: 16, marginBottom: 32 }}>
                {[
                  { label: "Total Users", value: "1,247", icon: "👥", color: "#6C63FF" },
                  { label: "Active Today", value: "83", icon: "🟢", color: "#43E97B" },
                  { label: "AI Requests/Day", value: "4,820", icon: "🤖", color: "#4ECDC4" },
                  { label: "Revenue", value: "$0 (Free)", icon: "💎", color: "#FFD93D" },
                ].map((stat, i) => (
                  <div key={stat.label} style={{ background: "var(--bg-card)", border: "1px solid rgba(255,255,255,0.06)", borderRadius: 16, padding: 20 }}>
                    <div style={{ fontSize: 28, marginBottom: 8 }}>{stat.icon}</div>
                    <div style={{ fontSize: 22, fontWeight: 800, color: stat.color }}>{stat.value}</div>
                    <div style={{ fontSize: 12, color: "var(--text-muted)" }}>{stat.label}</div>
                  </div>
                ))}
              </div>
              <div style={{ background: "var(--bg-card)", border: "1px solid rgba(255,255,255,0.06)", borderRadius: 16, padding: 24 }}>
                <h3 style={{ fontWeight: 700, marginBottom: 16 }}>Recent Activity Log</h3>
                {[
                  "User priya@example.com registered via Google",
                  "Mock interview session completed — Score: 87%",
                  "PDF uploaded: react_tutorial.pdf (156 pages)",
                  "New batch 'Full Stack March 2024' created",
                  "AI model router: 420 Gemini Flash requests today",
                ].map((log, i) => (
                  <div key={i} style={{ padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,0.04)", fontSize: 13, color: "var(--text-secondary)", display: "flex", gap: 10 }}>
                    <span style={{ color: "#43E97B", fontSize: 10 }}>●</span>{log}
                  </div>
                ))}
              </div>
            </div>
          )}

          {section === "Users" && (
            <div>
              <h1 style={{ fontSize: 24, fontWeight: 800, fontFamily: "Outfit", marginBottom: 24 }}>👥 User Management</h1>
              <div style={{ background: "var(--bg-card)", borderRadius: 16, border: "1px solid rgba(255,255,255,0.06)", overflow: "hidden" }}>
                <div style={{ padding: "16px 20px", borderBottom: "1px solid rgba(255,255,255,0.06)", display: "grid", gridTemplateColumns: "1fr 1fr 100px 80px 80px", gap: 16, fontSize: 11, fontWeight: 700, textTransform: "uppercase", color: "var(--text-muted)", letterSpacing: 1 }}>
                  <span>Name</span><span>Email</span><span>Role</span><span>Joined</span><span>Status</span>
                </div>
                {mockUsers.map((u, i) => (
                  <div key={i} style={{ padding: "14px 20px", borderBottom: "1px solid rgba(255,255,255,0.03)", display: "grid", gridTemplateColumns: "1fr 1fr 100px 80px 80px", gap: 16, alignItems: "center" }}>
                    <span style={{ fontSize: 14, fontWeight: 600 }}>{u.name}</span>
                    <span style={{ fontSize: 13, color: "var(--text-secondary)" }}>{u.email}</span>
                    <span className="badge badge-primary" style={{ fontSize: 10, width: "fit-content" }}>{u.role}</span>
                    <span style={{ fontSize: 12, color: "var(--text-muted)" }}>{u.joined}</span>
                    <span style={{ fontSize: 11, fontWeight: 600, color: u.active ? "#43E97B" : "rgba(255,255,255,0.3)" }}>{u.active ? "● Active" : "○ Inactive"}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {section === "Feature Toggles" && (
            <div>
              <h1 style={{ fontSize: 24, fontWeight: 800, fontFamily: "Outfit", marginBottom: 24 }}>⚡ Feature Toggles</h1>
              <p style={{ color: "var(--text-secondary)", fontSize: 14, marginBottom: 24 }}>Enable or disable platform features without deploying code.</p>
              <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                {features.map((f) => (
                  <div key={f.key} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 20px", background: "var(--bg-card)", border: "1px solid rgba(255,255,255,0.06)", borderRadius: 12 }}>
                    <div>
                      <div style={{ fontSize: 14, fontWeight: 600 }}>{f.label}</div>
                      <div style={{ fontSize: 11, color: "var(--text-muted)", fontFamily: "monospace" }}>{f.key}</div>
                    </div>
                    <div
                      onClick={() => setToggles(t => ({ ...t, [f.key]: !t[f.key] }))}
                      style={{
                        width: 48, height: 26, borderRadius: 13, cursor: "pointer",
                        background: toggles[f.key] ? "linear-gradient(135deg,#6C63FF,#4ECDC4)" : "rgba(255,255,255,0.1)",
                        position: "relative", transition: "all 0.3s",
                      }}
                    >
                      <div style={{ width: 20, height: 20, borderRadius: "50%", background: "white", position: "absolute", top: 3, left: toggles[f.key] ? 25 : 3, transition: "left 0.3s", boxShadow: "0 2px 6px rgba(0,0,0,0.3)" }} />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {section === "AI Usage" && (
            <div>
              <h1 style={{ fontSize: 24, fontWeight: 800, fontFamily: "Outfit", marginBottom: 24 }}>🤖 AI Usage Monitoring</h1>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 16, marginBottom: 24 }}>
                {[
                  { model: "Gemini Flash", requests: 2840, limit: "Unlimited (Free)", color: "#4285F4" },
                  { model: "Groq Llama 3", requests: 1240, limit: "14,400 req/day", color: "#43E97B" },
                  { model: "DeepSeek Coder", requests: 740, limit: "500k tokens/day", color: "#FF6B9D" },
                ].map(m => (
                  <div key={m.model} style={{ background: "var(--bg-card)", border: `1px solid ${m.color}33`, borderRadius: 16, padding: 20 }}>
                    <div style={{ fontSize: 22, fontWeight: 800, color: m.color }}>{m.requests.toLocaleString()}</div>
                    <div style={{ fontSize: 13, fontWeight: 600, marginTop: 4 }}>{m.model}</div>
                    <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 4 }}>{m.limit}</div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {(section === "Batches" || section === "Content") && (
            <div style={{ textAlign: "center", paddingTop: 80 }}>
              <div style={{ fontSize: 60, marginBottom: 16 }}>🚧</div>
              <h2 style={{ fontSize: 20, fontWeight: 700, marginBottom: 8 }}>{section} — Coming Soon</h2>
              <p style={{ color: "var(--text-secondary)" }}>This section is under active development.</p>
            </div>
          )}
        </motion.div>
      </div>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSelector, useDispatch } from "react-redux";
import { addMessage, setLoading } from "@/store/slices/chatSlice";
import { RootState } from "@/store";

export default function ChatPage() {
  const dispatch = useDispatch();
  const { messages, isLoading } = useSelector((s: RootState) => s.chat);
  const [input, setInput] = useState("");
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isLoading]);

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;
    const userMessage = { id: Date.now().toString(), role: "user" as const, content: input, timestamp: Date.now() };
    dispatch(addMessage(userMessage));
    const userInput = input;
    setInput("");
    dispatch(setLoading(true));

    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: userInput, session_id: "default" }),
      });
      const data = await res.json();
      dispatch(addMessage({ id: (Date.now() + 1).toString(), role: "assistant", content: data.response || "Sorry, I couldn't process that.", timestamp: Date.now() }));
    } catch {
      dispatch(addMessage({ id: (Date.now() + 1).toString(), role: "assistant", content: "I'm having trouble connecting to the server. Please try again.", timestamp: Date.now() }));
    } finally {
      dispatch(setLoading(false));
    }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "calc(100vh - 112px)", maxWidth: 900, margin: "0 auto" }}>
      {/* Header */}
      <div style={{ marginBottom: 20 }}>
        <h1 style={{ fontSize: 24, fontWeight: 800, fontFamily: "Outfit" }}>🤖 AI Chat</h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 13, marginTop: 4 }}>RAG-powered AI with conversation memory — ask anything!</p>
      </div>

      {/* Chat area */}
      <div style={{
        flex: 1,
        overflowY: "auto",
        background: "var(--bg-card)",
        borderRadius: 16,
        border: "1px solid rgba(255,255,255,0.06)",
        padding: 24,
        display: "flex",
        flexDirection: "column",
        gap: 20,
        marginBottom: 16,
      }}>
        {messages.length === 0 && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16, opacity: 0.5 }}>
            <div style={{ fontSize: 56 }}>🤖</div>
            <div style={{ fontFamily: "Outfit", fontSize: 20, fontWeight: 700 }}>How can I help you today?</div>
            <div style={{ color: "var(--text-muted)", fontSize: 14, textAlign: "center", maxWidth: 400 }}>
              Ask me anything about programming, career advice, concepts, or upload a PDF to discuss.
            </div>
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center", marginTop: 8 }}>
              {["Explain React hooks", "Python career path", "How to prepare for DSA?", "Review my code"].map(s => (
                <button key={s} onClick={() => setInput(s)} style={{
                  padding: "6px 14px",
                  borderRadius: 20,
                  border: "1px solid rgba(108,99,255,0.3)",
                  background: "rgba(108,99,255,0.08)",
                  color: "var(--brand-primary)",
                  fontSize: 12,
                  cursor: "pointer",
                  fontWeight: 500,
                }}>
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg) => (
          <motion.div key={msg.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}>
            {msg.role === "user" ? (
              <div style={{ display: "flex", justifyContent: "flex-end" }}>
                <div className="chat-message-user">{msg.content}</div>
              </div>
            ) : (
              <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
                <div style={{ width: 32, height: 32, borderRadius: "50%", background: "linear-gradient(135deg,#6C63FF,#4ECDC4)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14, flexShrink: 0 }}>🤖</div>
                <div className="chat-message-ai" style={{ whiteSpace: "pre-wrap" }}>{msg.content}</div>
              </div>
            )}
          </motion.div>
        ))}

        {isLoading && (
          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <div style={{ width: 32, height: 32, borderRadius: "50%", background: "linear-gradient(135deg,#6C63FF,#4ECDC4)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>🤖</div>
            <div style={{ display: "flex", gap: 6, alignItems: "center", padding: "10px 14px", background: "var(--bg-card)", borderRadius: 12, border: "1px solid rgba(255,255,255,0.06)" }}>
              <div className="typing-dot" /><div className="typing-dot" /><div className="typing-dot" />
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div style={{ display: "flex", gap: 12, alignItems: "flex-end" }}>
        <textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
          placeholder="Ask anything... (Enter to send, Shift+Enter for new line)"
          rows={2}
          style={{
            flex: 1,
            background: "rgba(255,255,255,0.04)",
            border: "1px solid rgba(255,255,255,0.08)",
            borderRadius: 12,
            padding: "14px 16px",
            color: "white",
            fontSize: 14,
            resize: "none",
            outline: "none",
            fontFamily: "Inter",
            transition: "border-color 0.2s",
          }}
          onFocus={(e) => (e.target.style.borderColor = "rgba(108,99,255,0.4)")}
          onBlur={(e) => (e.target.style.borderColor = "rgba(255,255,255,0.08)")}
        />
        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          onClick={sendMessage}
          disabled={isLoading || !input.trim()}
          style={{
            background: input.trim() ? "linear-gradient(135deg,#6C63FF,#4ECDC4)" : "rgba(255,255,255,0.08)",
            border: "none",
            borderRadius: 12,
            width: 48,
            height: 48,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            cursor: input.trim() ? "pointer" : "not-allowed",
            flexShrink: 0,
            transition: "all 0.2s",
          }}
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5">
            <path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z"/>
          </svg>
        </motion.button>
      </div>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { toggleSidebar } from "@/store/slices/uiSlice";
import { RootState } from "@/store";
import Sidebar from "@/components/dashboard/Sidebar";
import TopBar from "@/components/dashboard/TopBar";
import { motion, AnimatePresence } from "framer-motion";

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const { data: session, status } = useSession();
  const router = useRouter();
  const dispatch = useDispatch();
  const sidebarOpen = useSelector((s: RootState) => s.ui.sidebarOpen);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/auth");
    }
  }, [status, router]);

  if (status === "loading") {
    return (
      <div style={{
        minHeight: "100vh",
        background: "var(--bg-primary)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        flexDirection: "column",
        gap: 16,
      }}>
        <div style={{
          width: 60, height: 60, borderRadius: "50%",
          border: "3px solid rgba(108,99,255,0.2)",
          borderTopColor: "#6C63FF",
          animation: "spin 0.8s linear infinite",
        }} />
        <p style={{ color: "var(--text-secondary)", fontSize: 14 }}>Loading your workspace...</p>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  if (!session) return null;

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "var(--bg-primary)" }}>
      {/* Sidebar */}
      <AnimatePresence mode="wait">
        {sidebarOpen && (
          <motion.div
            initial={{ x: -280, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -280, opacity: 0 }}
            transition={{ duration: 0.2, ease: "easeOut" }}
            style={{ position: "fixed", left: 0, top: 0, bottom: 0, zIndex: 50 }}
          >
            <Sidebar />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Main content */}
      <div style={{
        flex: 1,
        marginLeft: sidebarOpen ? 260 : 0,
        transition: "margin-left 0.2s ease",
        display: "flex",
        flexDirection: "column",
        minHeight: "100vh",
      }}>
        <TopBar />
        <main style={{ flex: 1, padding: "24px", overflowY: "auto" }}>
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.3 }}
          >
            {children}
          </motion.div>
        </main>
      </div>
    </div>
  );
}

"use client";

import { useState, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";

interface Message { role: "user" | "assistant"; content: string; }

export default function PDFPage() {
  const [file, setFile] = useState<File | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleUpload = async (f: File) => {
    setFile(f);
    setIsUploading(true);
    const form = new FormData();
    form.append("file", f);
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/pdf/upload`, { method: "POST", body: form });
      const data = await res.json();
      setSessionId(data.session_id);
      setMessages([{ role: "assistant", content: `✅ **${f.name}** uploaded successfully! I've processed ${data.pages || "all"} pages. Ask me anything about this document.` }]);
    } catch {
      setMessages([{ role: "assistant", content: "Failed to upload PDF. Please try again." }]);
    } finally {
      setIsUploading(false);
    }
  };

  const askQuestion = async () => {
    if (!input.trim() || isLoading || !sessionId) return;
    const q = input;
    setInput("");
    setMessages(prev => [...prev, { role: "user", content: q }]);
    setIsLoading(true);
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/api/pdf/ask`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ question: q, session_id: sessionId }),
      });
      const data = await res.json();
      setMessages(prev => [...prev, { role: "assistant", content: data.answer || "Could not process your question." }]);
    } catch {
      setMessages(prev => [...prev, { role: "assistant", content: "Error connecting to server." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 820, margin: "0 auto" }}>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 800, fontFamily: "Outfit" }}>📄 PDF Q&A System</h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 13, marginTop: 4 }}>Upload any PDF and chat with it using AI</p>
      </div>

      {/* Upload Area */}
      {!file ? (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          onClick={() => fileRef.current?.click()}
          onDrop={(e) => { e.preventDefault(); const f = e.dataTransfer.files[0]; if (f?.type === "application/pdf") handleUpload(f); }}
          onDragOver={(e) => e.preventDefault()}
          style={{
            border: "2px dashed rgba(108,99,255,0.3)",
            borderRadius: 20,
            padding: "60px 40px",
            textAlign: "center",
            cursor: "pointer",
            background: "rgba(108,99,255,0.04)",
            transition: "all 0.3s ease",
            marginBottom: 24,
          }}
          onMouseEnter={(e) => { (e.currentTarget as HTMLDivElement).style.borderColor = "rgba(108,99,255,0.6)"; (e.currentTarget as HTMLDivElement).style.background = "rgba(108,99,255,0.08)"; }}
          onMouseLeave={(e) => { (e.currentTarget as HTMLDivElement).style.borderColor = "rgba(108,99,255,0.3)"; (e.currentTarget as HTMLDivElement).style.background = "rgba(108,99,255,0.04)"; }}
        >
          <div style={{ fontSize: 56, marginBottom: 16 }}>📤</div>
          <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 8 }}>Drop your PDF here</div>
          <div style={{ color: "var(--text-secondary)", fontSize: 14 }}>or click to browse files</div>
          <input ref={fileRef} type="file" accept=".pdf" style={{ display: "none" }} onChange={(e) => { const f = e.target.files?.[0]; if (f) handleUpload(f); }} />
        </motion.div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", height: "calc(100vh - 200px)" }}>
          {/* File info */}
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16, padding: "12px 16px", background: "rgba(108,99,255,0.1)", borderRadius: 12, border: "1px solid rgba(108,99,255,0.2)" }}>
            <span style={{ fontSize: 24 }}>📄</span>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 14, fontWeight: 600 }}>{file.name}</div>
              <div style={{ fontSize: 12, color: "var(--text-muted)" }}>{(file.size / 1024 / 1024).toFixed(2)} MB</div>
            </div>
            <button onClick={() => { setFile(null); setMessages([]); setSessionId(null); }} style={{ background: "transparent", border: "none", color: "var(--text-muted)", cursor: "pointer", fontSize: 18 }}>✕</button>
          </div>

          {/* Messages */}
          <div style={{ flex: 1, overflowY: "auto", background: "var(--bg-card)", borderRadius: 16, border: "1px solid rgba(255,255,255,0.06)", padding: 20, marginBottom: 16, display: "flex", flexDirection: "column", gap: 16 }}>
            {isUploading && (
              <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                <div style={{ width: 30, height: 30, borderRadius: "50%", border: "2px solid #6C63FF", borderTopColor: "transparent", animation: "spin 0.8s linear infinite" }} />
                <span style={{ color: "var(--text-secondary)", fontSize: 14 }}>Processing your PDF...</span>
              </div>
            )}
            {messages.map((msg, i) => (
              <div key={i} style={{ display: "flex", justifyContent: msg.role === "user" ? "flex-end" : "flex-start" }}>
                <div className={msg.role === "user" ? "chat-message-user" : "chat-message-ai"}>{msg.content}</div>
              </div>
            ))}
            {isLoading && <div style={{ display: "flex", gap: 6, padding: "10px 14px", background: "var(--bg-card)", borderRadius: 12, border: "1px solid rgba(255,255,255,0.06)", width: "fit-content" }}><div className="typing-dot" /><div className="typing-dot" /><div className="typing-dot" /></div>}
          </div>

          {/* Input */}
          <div style={{ display: "flex", gap: 10 }}>
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && askQuestion()}
              placeholder={sessionId ? "Ask a question about your PDF..." : "Please wait for the PDF to be processed..."}
              disabled={!sessionId || isLoading}
              className="input-field"
            />
            <button onClick={askQuestion} disabled={!sessionId || isLoading || !input.trim()} style={{ background: "linear-gradient(135deg,#6C63FF,#4ECDC4)", border: "none", borderRadius: 10, padding: "0 20px", color: "white", fontWeight: 600, cursor: "pointer", fontSize: 14, whiteSpace: "nowrap" }}>
              Ask
            </button>
          </div>
        </div>
      )}
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

